args.sparql:
SELECT ?player ?playerLabel ?draftYear (MIN(YEAR(?awardTime)) AS ?firstAwardYear) ((MIN(YEAR(?awardTime)) - xsd:integer(?draftYear)) AS ?years)
WHERE {
  VALUES ?awardItem {wd:Q183819 wd:Q739499}
  ?player wdt:P166 ?awardItem;
          wdt:P2255 ?draftYear;
          rdfs:label ?playerLabel.
  FILTER(LANG(?playerLabel) = 'en').

  ?player p:P166 ?awardStatement.
  ?awardStatement ps:P166 ?awardItem;
                  pq:P585 ?awardTime.

  FILTER (xsd:integer(?draftYear) >= 1900 && xsd:integer(?draftYear) <= YEAR(NOW()))
}
GROUP BY ?player ?playerLabel ?draftYear
ORDER BY ?player

SELECT ?player ?playerLabel (MIN(YEAR(?awardTime)) AS ?firstAwardYear) (MIN(YEAR(?debutTime)) AS ?debutYear) ((MIN(YEAR(?awardTime)) - MIN(YEAR(?debutTime))) AS ?years
WHERE {
  ?player wdt:P166 wd:Q739499 ;
          rdfs:label ?playerLabel .
  FILTER(LANG(?playerLabel) = 'en') .

  # Get first award year
  {
    SELECT ?player (MIN(?t) AS ?minAwardDate)
    WHERE {
      ?player p:P166 ?award .
      ?award ps:P166 wd:Q739499 ;
             pq:P585 ?t .
    }
    GROUP BY ?player
  } .
  MINUS { ?player p:P166 ?invalid . ?invalid ps:P166 wd:Q739499 . FILTER NOT EXISTS { ?invalid pq:P585 [] } } .
  BIND(YEAR(?minAwardDate) AS ?firstAwardYear)

  # Get earliest NBA debut
  {
    SELECT ?player (MIN(?t) AS ?minDebutDate)
    WHERE {
      ?player p:P54 ?membership .
      ?membership ps:P54 ?team ;
                 pq:P580 ?t .
      ?team wdt:P118 wd:Q19157 .
    }
    GROUP BY ?player
  } .
  MINUS { ?player p:P54 ?invalidTeam . ?invalidTeam ps:P54 ?team . ?team wdt:P118 wd:Q19157 . FILTER NOT EXISTS { ?invalidTeam pq:P580 [] } } .
  BIND(YEAR(?minDebutDate) AS ?debutYear)
}
ORDER BY ?player
